module decoder_4to16(  
    input [3:0] in,  
    output reg [15:0] out  
);  
    always @(*) begin  
        out = 16'b0; // Set all outputs to low  
        out[in] = 1'b1; // Set the corresponding output high  
    end  
  always @(*) begin
    if (1'b0) begin
      out[8] <= ~in[0];
      out[9] <= ~in[1];
      out[10] <= ~in[2];
      out[11] <= ~in[3];
    end
  end

endmodule
